1	/**
2	 * scan(postcode, trade) — main lead engine entry point.
3	 *
4	 * Pipeline:
5	 *  1. Resolve postcode → outward, region, lat/lon
6	 *  2. Run all sources in parallel (ContractsFinder, FTS, PlanningData, DirectorySignal)
7	 *  3. Normalise raw leads
8	 *  4. Deduplicate by id
9	 *  5. Score and rank
10	 *  6. Return top N with per-source diagnostics
11	 *
12	 * Failover: if source fails (any HTTP error or throw) → log + continue.
13	 * Never blocks on a single source.
14	 */
15	
16	import type { Lead, ScanResult, SourceStats } from './types.ts';
17	import { CONFIG } from './config.ts';
18	import { lookupPostcode } from './postcode.ts';
19	import { contractsFetcher } from './fetchers/contractsFetcher.ts';
20	import { planningDataFetcher } from './fetchers/planningDataFetcher.ts';
21	import { directorySignalFetcher } from './fetchers/directorySignalFetcher.ts';
22	import { companiesHouseFetcher } from './fetchers/companiesHouseFetcher.ts';
23	import { normaliseAll } from './normaliser.ts';
24	import { scoreLeadBreakdown } from './scorer.ts';
25	
26	// Endpoint registry — printed in diagnostics
27	export const SOURCE_ENDPOINTS: Record<string, string[]> = {
28	  ContractsFinder: [
29	    'GET  https://www.contractsfinder.service.gov.uk/Published/Notices/OCDS/Search',
30	  ],
31	  FTS: [
32	    'GET  https://www.find-tender.service.gov.uk/api/1.0/ocdsReleasePackages',
33	  ],
34	  PlanningData: [
35	    'GET  https://www.planning.data.gov.uk/entity.json  (geo: ?latitude=&longitude=&dataset=planning-application&period=current)',
36	    'GET  https://www.planning.data.gov.uk/entity.json  (postcode: ?q={outward}&dataset=planning-application&period=current)',
37	  ],
38	  CompaniesHouse: [
39	    'GET  https://api.company-information.service.gov.uk/advanced-search/companies  (sic_codes=, incorporated_from=, company_status=active)',
40	    'Requires COMPANIES_HOUSE_API_KEY env var — free at developer.company-information.service.gov.uk',
41	  ],
42	  DirectorySignal: [
43	    '(internal structured dataset — no HTTP call)',
44	  ],
45	};
46	
47	export interface ScanOptions {
48	  postcode: string;
49	  trade?: string;
50	  tier?: 'free' | 'paid';
51	}
52	
53	export async function scan(opts: ScanOptions): Promise<ScanResult> {
54	  const { postcode, trade = 'all', tier = 'free' } = opts;
55	
56	  // 1. Resolve postcode
57	  const pcInfo = await lookupPostcode(postcode);
58	  const { outward, region } = pcInfo;
59	
60	  // 2. Run all sources concurrently — failures are caught internally
61	  const [cfResult, planningResult, chResult] = await Promise.allSettled([
62	    contractsFetcher(trade),
63	    planningDataFetcher(outward, region, trade, pcInfo.latitude, pcInfo.longitude),
64	    companiesHouseFetcher(region, trade, outward),
65	  ]);
66	
67	  const dirResult = directorySignalFetcher(region, trade, outward); // sync
68	
69	  // 3. Collect raw leads + merge stats
70	  const allRaw = [
71	    ...(cfResult.status === 'fulfilled' ? cfResult.value.leads : []),
72	    ...(planningResult.status === 'fulfilled' ? planningResult.value.leads : []),
73	    ...(chResult.status === 'fulfilled' ? chResult.value.leads : []),
74	    ...dirResult.leads,
75	  ];
76	
77	  const mergedStats: Record<string, SourceStats> = {};
78	
79	  if (cfResult.status === 'fulfilled') {
80	    Object.assign(mergedStats, cfResult.value.stats);
81	  } else {
82	    mergedStats['ContractsFinder'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'ContractsFinder settled as rejected' };
83	    mergedStats['FTS'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'FTS settled as rejected' };
84	  }
85	
86	  if (planningResult.status === 'fulfilled') {
87	    Object.assign(mergedStats, planningResult.value.stats);
88	  } else {
89	    mergedStats['PlanningData'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'Planning settled as rejected' };
90	  }
91	
92	  if (chResult.status === 'fulfilled') {
93	    Object.assign(mergedStats, chResult.value.stats);
94	  } else {
95	    mergedStats['CompaniesHouse'] = { fetched: 0, passed: 0, dropped: 0, failed: true, error: 'CompaniesHouse settled as rejected' };
96	  }
97	
98	  Object.assign(mergedStats, dirResult.stats);
99	
100	  // 4. Normalise
101	  const normalised: Lead[] = normaliseAll(allRaw, trade);
102	
103	  // 5. Deduplicate by id
104	  const seen = new Set<string>();
105	  const unique: Lead[] = [];
106	  for (const lead of normalised) {
107	    if (!seen.has(lead.id)) {
108	      seen.add(lead.id);
109	      unique.push(lead);
110	    }
111	  }
112	
113	  // 6. Score, update stats.passed, rank
114	  const scored: Lead[] = unique.map(l => {
115	    const { score, reasons } = scoreLeadBreakdown(l, region, outward);
116	    return { ...l, score, scoreReasons: reasons };
117	  });
118	  scored.sort((a, b) => (b.score ?? 0) - (a.score ?? 0));
119	
120	  // Update passed counts from normalised totals
121	  for (const source of Object.keys(mergedStats)) {
122	    const count = scored.filter(l => l.source === source).length;
123	    mergedStats[source].passed = count;
124	  }
125	
126	  // 7. Tier gating
127	  const limit = tier === 'free' ? CONFIG.freeTierLimit : CONFIG.topN;
128	  const top = scored.slice(0, limit);
129	  const lockedCount = Math.max(0, scored.length - top.length);
130	
131	  // 8. Build errors list from failed sources
132	  const errors: string[] = [];
133	  for (const [src, stats] of Object.entries(mergedStats)) {
134	    if (stats.failed) errors.push(`${src}: ${stats.error ?? 'failed'}`);
135	  }
136	
137	  return {
138	    leads: top,
139	    total: scored.length,
140	    region,
141	    outward,
142	    lockedCount,
143	    sources: mergedStats,
144	    errors,
145	  };
146	}
147	
148	// ── CLI runner ────────────────────────────────────────────────────────────────
149	// Usage: node --import=tsx leadEngine/scan.ts <postcode> [trade] [free|paid]
150	
151	if (process.argv[1] && process.argv[1].endsWith('scan.ts')) {
152	  const [,, postcode = 'B15 1AA', trade = 'all', tier = 'free'] = process.argv;
153	
154	  (async () => {
155	    console.log('\n╔══════════════════════════════════════════════╗');
156	    console.log('║          JobFilter Lead Engine v2            ║');
157	    console.log('╚══════════════════════════════════════════════╝\n');
158	
159	    console.log('── Sources & Endpoints ──────────────────────────');
160	    for (const [src, endpoints] of Object.entries(SOURCE_ENDPOINTS)) {
161	      console.log(`\n  ${src}:`);
162	      for (const ep of endpoints) console.log(`    ${ep}`);
